H-Minimum-cost Flow 设 cost(u/v, 1) 表示容量为u/v，流量为1的总花费。
我们可以把网络扩大v/u倍，之后 cost(u/v,1) * (v/u) = cost(1, v/u)。
这样所有的边的容量都是1，我们可以跑mcmf，记录每一条增广路的价值。因为容量是1，因此每有一条增广路，总流量会加一。
因为每条增广路的价值是不减的，因此我们一定是顺序取，直到流量等于v/u。
别忘了最后乘以u/v，把网络缩小到原来的样子。
#include &lt;bits/stdc++.h&gt;using namespace std; using ll = long long; const int INF = 0x3f3f3f; const int maxn = 105; vector&lt;ll&gt; val; ll sum[maxn]; struct Edge { int from, to, cap, flow, cost; Edge(int u, int v, int c, int f, int w) : from(u), to(v), cap(c), flow(f), cost(w) {} }; struct MCMF { int n, m; vector&lt;Edge&gt; edges; vector&lt;int&gt; G[maxn]; int inq[maxn]; //是否在队列中  int d[maxn]; // bellmanford 到源点距离  int p[maxn]; //上一条弧  int a[maxn]; //可改进量  void init(int n) { this-&gt;n = n; for (int i = 0; i &lt;= n; i++) G[i].clear(); edges.clear(); } void AddEdge(int from, int to, int cap, int cost) { edges.push_back(Edge(from, to, cap, 0, cost)); edges.push_back(Edge(to, from, 0, 0, -cost)); m = edges.size(); G[from].push_back(m - 2); G[to].push_back(m - 1); } bool BellmanFord(int s, int t, int&amp; flow, ll&amp; cost) { for (int i = 0; i &lt;= n; i++) d[i] = INF; for (int i = 0; i &lt;= n; i++) inq[i] = 0; d[s] = 0; inq[s] = 1; p[s] = 0; a[s] = INF; queue&lt;int&gt; Q; Q.push(s); while (!Q.empty()) { int u = Q.front(); Q.pop(); inq[u] = 0; for (int i = 0; i &lt; G[u].size(); i++) { Edge&amp; e = edges[G[u][i]]; if (e.cap &gt; e.flow &amp;&amp; d[e.to] &gt; d[u] + e.cost) { d[e.to] = d[u] + e.cost; p[e.to] = G[u][i]; a[e.to] = min(a[u], e.cap - e.flow); if (!inq[e.to]) { Q.push(e.to); inq[e.to] = 1; } } } } if (d[t] == INF) return false; // 当没有可增广的路时退出  flow += a[t]; cost += (ll)d[t] * (ll)a[t]; val.push_back((ll)d[t] * (ll)a[t]); for (int u = t; u != s; u = edges[p[u]].from) { edges[p[u]].flow += a[t]; edges[p[u] ^ 1].flow -= a[t]; } return true; } int MincostMaxflow(int s, int t, ll&amp; cost) { int flow = 0; cost = 0; while (BellmanFord(s, t, flow, cost)) ; return flow; } } mcmf; int main() { int n, m, q; while (~scanf(&#34;%d%d&#34;, &amp;n, &amp;m)) { mcmf.init(n); val.clear(); for (int i = 0, u, v, w; i &lt; m; i++) { scanf(&#34;%d%d%d&#34;, &amp;u, &amp;v, &amp;w); mcmf.AddEdge(u, v, 1, w); } ll uesless; mcmf.MincostMaxflow(1, n, uesless); for (int i = 1; i &lt;= val.size(); i++) sum[i] = sum[i - 1] + val[i - 1]; scanf(&#34;%d&#34;, &amp;q); for (int i = 0, u, v; i &lt; q; i++) { scanf(&#34;%d%d&#34;, &amp;u, &amp;v); if (!u || (v + u - 1) / u &gt; val.size()) { puts(&#34;NaN&#34;); continue; } int x = v / u, y = v % u; ll num = sum[x] * u + val[x] * y, den = v; ll d = __gcd(num, den); printf(&#34;%lld/%lld\\n&#34;, num / d, den / d); } } }

题意 三种操作：
 c1 到 c2 链上都增加k c1 到 c2 链上都减少k 查询c1 到c2 链上的和  分析 轻重链剖分后用树状数组维护即可。
代码 // ybmj #include &lt;bits/stdc++.h&gt;using namespace std; #define lson (rt &lt;&lt; 1) #define rson (rt &lt;&lt; 1 | 1) #define lson_len (len - (len &gt;&gt; 1)) #define rson_len (len &gt;&gt; 1) #define pb(x) push_back(x) #define clr(a, x) memset(a, x, sizeof(a)) #define mp(x, y) make_pair(x, y) typedef long long ll; typedef pair&lt;int, int&gt; pii; typedef pair&lt;ll, ll&gt; pll; const int INF = 0x3f3f3f3f; const int NINF = 0xc0c0c0c0; const int maxn = 5e4+5; int a[maxn]; struct HLD { int n, dfn; int sz[maxn], top[maxn], son[maxn], dep[maxn], par[maxn], id[maxn], rk[maxn]; vector&lt;int&gt; G[maxn]; void init(int n) { this-&gt;n = n; clr(son, -1); clr(diff, 0); dfn = 0; for (int i = 0; i &lt;= n; i++) G[i].clear(); } void addedge(int u, int v) { G[u].pb(v); G[v].pb(u); } void dfs(int u, int fa, int d) { dep[u] = d; par[u] = fa; sz[u] = 1; for (auto &amp;v : G[u]) { if (v == fa) continue; dfs(v, u, d + 1); sz[u] += sz[v]; if (son[u] == -1 || sz[v] &gt; sz[son[u]]) son[u] = v; } } void link(int u, int t) { top[u] = t; id[u] = ++dfn; rk[dfn] = u; if (son[u] == -1) return; link(son[u], t); for (auto &amp;v : G[u]) { if (v != son[u] &amp;&amp; v != par[u]) link(v, v); } } void update_path(int u, int v, int val) { while (top[u] != top[v]) { if (dep[top[u]] &lt; dep[top[v]]) swap(u, v); update(id[top[u]], id[u], val); u = par[top[u]]; } if (dep[u] &gt; dep[v]) swap(u, v); update(id[u], id[v], val); } int diff[maxn]; int lowb(int x) { return x &amp; (-x); } int query(int x) { int ret = 0; for (int i = x; i &gt; 0; i -= lowb(i)) { ret += diff[i]; continue; } return ret; } void update(int l, int r, int val) { for (int i = l; i &lt;= n; i += lowb(i)) diff[i] += val; for (int i = r + 1; i &lt;= n; i += lowb(i)) diff[i] -= val; } }; HLD hld; int main() { // /* #ifndef ONLINE_JUDGE  freopen(&#34;1.in&#34;, &#34;r&#34;, stdin); freopen(&#34;1.out&#34;, &#34;w&#34;, stdout); #endif  // */  std::ios::sync_with_stdio(false); int n, m, q; while (cin &gt;&gt; n &gt;&gt; m &gt;&gt; q) { hld.init(n + 5); for (int i = 1; i &lt;= n; i++) cin &gt;&gt; a[i]; int u, v, w; for (int i = 0; i &lt; m; i++) { cin &gt;&gt; u &gt;&gt; v; hld.addedge(u, v); } hld.dfs(1, 1, 1); hld.link(1, 1); for (int i = 1; i &lt;= n; i++) hld.update(hld.id[i], hld.id[i], a[i]); string op; for (int i = 0; i &lt; q; i++) { cin &gt;&gt; op; if (op == &#34;I&#34;) { cin &gt;&gt; u &gt;&gt; v &gt;&gt; w; hld.update_path(u, v, w); } else if (op == &#34;D&#34;) { cin &gt;&gt; u &gt;&gt; v &gt;&gt; w; hld.update_path(u, v, -w); } else { cin &gt;&gt; u; cout &lt;&lt; hld.query(hld.id[u]) &lt;&lt; endl; } } } }

kruskal 贪心+并查集
从权值最小的边开始遍历，若当前两个点在一个连通分量里，则忽略。
否则选取这条边加入到最小生成树中，当选取 n-1 条边后停止，因为只需要 n-1 条边即可连接 n 个点。
若图不连通，则会出现问题&hellip;
可以稍微模改一下 (●'◡'●)
模板 const int maxn = 10; struct Edge { int u, v, w; Edge(int u = 0, int v = 0, int w = 0) : u(u), v(v), w(w) {} bool operator&lt;(const Edge &amp;A) const { return w &lt; A.w; } }; vector&lt;Edge&gt; edges; int par[maxn]; void addedge(int u, int v, int w) { edges.push_back(Edge(u, v, w)); // edges.push_back(Edge(v, u, w)); } int find(int x) { return par[x] == x ? x : find(par[x]); } int kruskal(int n) { int ans = 0; for (int i = 0; i &lt; n; i++) par[i] = i; sort(edges.begin(), edges.end()); //按权值排序  int cnt = 0; for (int i = 0; i &lt; edges.size(); i++) { if (cnt &gt;= n - 1) break; Edge &amp;now = edges[i]; int x = find(now.u); int y = find(now.v); if (x != y) { cnt++; par[x] = y; ans += now.w; } } return ans; }

区间众数 分块。
num[x]表示区间内x出现了几次。 cnt[x]表示区间内出现次数为x的数字有几个。
#include &lt;bits/stdc++.h&gt;using namespace std; const int maxn = 3e5 + 5; int a[maxn], ans[maxn]; struct Query { int l, r, id; } Q[maxn]; int S; bool cmp(const Query&amp; A, const Query&amp; B) { if (A.l / S == B.l / S) return A.r &lt; B.r; return A.l &lt; B.l; } int num[maxn], cnt[maxn]; int mx; void pls(int x) { cnt[num[a[x]]]--; num[a[x]]++; cnt[num[a[x]]]++; if (num[a[x]] &gt; mx) mx = num[a[x]]; } void sbs(int x) { cnt[num[a[x]]]--; num[a[x]]--; cnt[num[a[x]]]++; if (cnt[mx] == 0) mx--; } int main() { int n, q; scanf(&#34;%d%d&#34;, &amp;n, &amp;q); S = sqrt(n); for (int i = 0; i &lt; n; i++) scanf(&#34;%d&#34;, a + i); for (int i = 0; i &lt; q; i++) { scanf(&#34;%d%d&#34;, &amp;Q[i].l, &amp;Q[i].r); Q[i].l--; Q[i].id = i; } sort(Q, Q + q, cmp); int l = 0, r = 0; mx = 0; for (int i = 0; i &lt; q; i++) { while (r &lt; Q[i].r) pls(r++); while (l &gt; Q[i].l) pls(--l); while (r &gt; Q[i].r) sbs(--r); while (l &lt; Q[i].l) sbs(l++); ans[Q[i].id] = mx; } for (int i = 0; i &lt; q; i++) printf(&#34;%d\\n&#34;, ans[i]); }

参考文章： 2009NOI 国家集训队论文——罗穗骞
代码解释 sa[i]：表示排名为i的后缀的起始位置
rank[i]：表示从i开始的后缀的排名
height[i] = LCP(suffix(sa[i-1]), suffix(sa[i]))：排名为i-1和排名为i的两个后缀的最长公共前缀
h[i] = height[rank[i]]：起始位置为i的后缀和它前一名的后缀的最长公共前缀
性质：
 $suffix(i)$和$suffix(k)$的最长公共前缀为$height[rank[i]+1]&hellip;height[rank[k]]$中的最小值。 $h[i] \geq h[i-1] - 1$  例题 {% note primary %}
给定一个字符串，求某两个后缀的最长公共前缀 性质：LCP(suffix(i), suffix(j)) = min { height[rank[i]+1], ..., height[rank[j]] } 因此可以用rmq预处理区间最小值，然后 O(1)查询 {% endnote %}
{% note info %}
可重叠最长重复子串 重复子串：若字符串R在字符串L中至少出现两次，则称R是L的重复子串 因为相邻排名的两个后缀串之间的lcp一定比不相邻的两个后缀串的lcp大，因此答案是height数组的最大值。 {% endnote %}
{% note success %}
不可重叠最长重复字串（poj1743） 二分答案，然后按答案对height进行分组，使得同一组内的后缀串相互之间的lcp都大于等于二分的答案。 如果一组内的最大的 sa 值减去最小的 sa 值大于等于二分的答案，那么就是可行的。用并查集维护一下就好。 要注意的是，本题是对差分后的数组建后缀数组，因此首先要保证数组元素非负，然后是差分后的公共前缀的长度的意义是不同的。 {% endnote %}
{% note primary %}
可重叠的出现至少 k 次的重复子串（poj3261） 同样还是按height分组的思想。二分答案，分组后要求同一组内的后缀串数量大于等于 k，则满足条件。 {% endnote %}
{% note info %}
本质不同的子串数量（spoj705） $ans = \sum_{i=1}^{n}(n-sa[i]-height[i])$ {% endnote %}
{% note success %}
最长回文子串（ural1297） 将字符串逆转后和原字符串拼接起来，拼接前要加一个从未出现过的字符在原字符串后面，这样可以防止匹配越界。 然后枚举回文串的中心点，讨论一下长度的奇偶。
{% endnote %}
{% note primary %}
连续重复子串（poj2406） 给定一个字符串$L$，已知这个字符串是由某个字符串$S$重复$R$次而得到的，求$R$的最大值。 枚举长度$k$，如果$lcp(0,0+k) == n-k$那么$k$是满足条件的，$R = \frac{n}{k}$，因此找到最小的$k$即可。 要注意字符串长度为$10^6$，直接建后缀数组是会$MLE$（因为$dp$数组爆了）。但是我们并不需要$rmq$，因为第一个参数一直为$0$，所以我们可以将$dp$数组降到一维。 {% endnote %}
{% note info %}
重复次数最多的连续重复子串（spoj687） 给定一个字符串$L$，求$L$的所有子串中重复次数最多的连续重复子串。 枚举长度$k$，那么$s[0],s[0+k]&hellip;,s[0+nk]$，中一定有两个相邻的会被选上，但显然这不一定是两个重复子串的开头。 开头可能会在前面$k-1$个位置中。 $n + \frac{n}{2} + \frac{n}{3} + &hellip;.. = n\log n$ {% endnote %}
{% note success %}
最长公共子串（ural1517） 给定两个字符串 $A$ 和 $B$，求最长公共子串。 将两个字符串拼接起来，中间加个从未出现的字符。排名相邻且不在同一字符串的两个后缀的 $lcp$ 的最大值为答案。 {% endnote %}
{% note primary %}
长度不小于 k 的公共子串的个数(pku3415) {% endnote %}
{% note info %}
不小于 k 个字符串中的最长子串(pku3294) {% endnote %}
{% note success %}
每个字符串至少出现两次且不重叠的最长子串(spoj220) {% endnote %}
{% note primary %}
出现或反转后出现在每个字符串中的最长子串(PKU3294) {% endnote %}
模板 // build 复杂度:O(nlogn) // 需要保证s[n]为之前没有出现过的最小的字符。必要时手动添加，或者自动&#39;\\0&#39;。 // sa下标从1开始编号，sa[0]表示加入的最小字符&#39;\\0&#39; struct SA { char s[maxn]; int sa[maxn], t[maxn], t2[maxn], c[maxn], rank[maxn], height[maxn]; int dp[maxn][30]; void build(int m, int n) { // [0,m-1]字符集, [0,n-1] 字符串  n++; int *x = t, *y = t2; for (int i = 0; i &lt; m; i++) c[i] = 0; for (int i = 0; i &lt; n; i++) c[x[i] = s[i]]++; for (int i = 1; i &lt; m; i++) c[i] += c[i - 1]; for (int i = n - 1; ~i; i--) sa[--c[x[i]]] = i; for (int k = 1; k &lt;= n; k &lt;&lt;= 1) { int p = 0; for (int i = n - k; i &lt; n; i++) y[p++] = i; for (int i = 0; i &lt; n; i++) if (sa[i] &gt;= k) y[p++] = sa[i] - k; for (int i = 0; i &lt; m; i++) c[i] = 0; for (int i = 0; i &lt; n; i++) c[x[y[i]]]++; for (int i = 1; i &lt; m; i++) c[i] += c[i - 1]; for (int i = n - 1; ~i; i--) sa[--c[x[y[i]]]] = y[i]; swap(x, y); p = 1; x[sa[0]] = 0; for (int i = 1; i &lt; n; i++) x[sa[i]] = y[sa[i - 1]] == y[sa[i]] &amp;&amp; y[sa[i - 1] + k] == y[sa[i] + k] ? p - 1 : p++; if (p &gt;= n) break; m = p; } n--; int k = 0; for (int i = 0; i &lt;= n; i++) rank[sa[i]] = i; for (int i = 0; i &lt; n; i++) { if (k) k--; int j = sa[rank[i] - 1]; while (s[i + k] == s[j + k]) k++; height[rank[i]] = k; // h[i] = height[rank[i]]  } } void initRmq(int n) { for (int i = 1; i &lt;= n; i++) dp[i][0] = height[i]; for (int j = 1; (1 &lt;&lt; j) &lt;= n; j++) for (int i = 1; i + (1 &lt;&lt; j) - 1 &lt;= n; i++) dp[i][j] = min(dp[i][j - 1], dp[i + (1 &lt;&lt; (j - 1))][j - 1]); } int rmq(int l, int r) { int k = 31 - __builtin_clz(r - l + 1); return min(dp[l][k], dp[r - (1 &lt;&lt; k) + 1][k]); } int lcp(int a, int b) { // 返回起始地址为a和b的两个后缀串的lcp  a = rank[a], b = rank[b]; if (a &gt; b) swap(a, b); return rmq(a + 1, b); } } sa;

最小表示法 对于 $s$ 的两个子串 $A,B$。
设 $k$ 满足：$A[i] = B[j], &hellip; , A[i+k-1] = B[j+k-1]$。
那么如果 $A[i+k] &gt; B[j+k]$ 那么最小表示的首元素一定不在 $A[i]&hellip;A[i+k]$ 中。
// 返回最小表示的首元素的下标 int work(string s) { int n = s.size(); int i, j, k; for (i = 0, j = 1, k = 0; i &lt; n &amp;&amp; j &lt; n &amp;&amp; k &lt; n;) { if (s[(i + k) % n] == s[(j + k) % n]) k++; else { if (s[(i + k) % n] &gt; s[(j + k) % n]) i = i + k + 1; else j = j + k + 1; if (i == j) i++; k = 0; } } return min(i, j); }

简介 启发式合并应该比较熟悉，并查集合并的时候为了防止退化，会让高度小的向高度大的合并，这也算一种启发式合并。
树上的启发式合并就是：假设我们现在想知道一棵树上所有节点的子树信息，那么在递归计算的过程中，可以选择保留重儿子的子树上的信息，然后再去重新计算其余儿子的子树信息。这样会使得复杂度由$O(n^2)$降为$O(nlog(n))$
