例题及模板 给一棵树，每个节点都有一个颜色，每次查询问某棵子树上颜色为c的节点数。
// 推荐使用 vector&lt;int&gt; *vec[maxn], G[maxn]; int cnt[maxn], sz[maxn], col[maxn]; bool vis[maxn], bigc[maxn]; int szdfs(int u, int fa) { sz[u] = vis[u] = 1; for (auto &amp;v : G[u]) if (v != fa &amp;&amp; !vis[v]) sz[u] += szdfs(v, u); return sz[u]; } void add(int u, int fa, int x) { cnt[col[u]] += x; for (auto &amp;v : G[u]) if (v != fa &amp;&amp; !bigc[v]) add(v, u, x); } void dfs(int u, int fa, bool keep) { int mx = -1, bc = -1; for (auto &amp;v : G[u]) if (v != fa &amp;&amp; sz[v] &gt; mx) { mx = sz[v]; bc = v; } for (auto &amp;v : G[u]) if (v != fa &amp;&amp; v != bc) dfs(v, u, 0); // run a dfs on small childs and clear them from cnt  if (bc != -1) { dfs(bc, u, 1); bigc[bc] = 1; } // bigChild marked as big and not cleared from cnt  add(u, fa, 1); // now cnt[c] is the number of vertices in subtree of vertex v that has  // color c. You can answer the queries easily.  if (bc != -1) bigc[bc] = 0; if (!keep) add(u, fa, -1); } // 多组数据就不要用了...指针可能还要delet？ vector&lt;int&gt; *vec[maxn], G[maxn]; int cnt[maxn], sz[maxn], col[maxn]; bool vis[maxn]; int szdfs(int u, int fa) { sz[u] = vis[u] = 1; for (auto &amp;v : G[u]) if (v != fa &amp;&amp; !vis[v]) sz[u] += szdfs(v, u); return sz[u]; } void dfs(int u, int fa, bool keep) { int mx = -1, bigChild = -1; for (auto &amp;v : G[u]) if (v != fa &amp;&amp; sz[v] &gt; mx) mx = sz[v], bigChild = v; for (auto &amp;v : G[u]) if (v != fa &amp;&amp; v != bigChild) dfs(v, u, 0); if (bigChild != -1) dfs(bigChild, u, 1), vec[u] = vec[bigChild]; else vec[u] = new vector&lt;int&gt;(); vec[u]-&gt;push_back(u); cnt[col[u]]++; for (auto &amp;v : G[u]) if (v != fa &amp;&amp; v != bigChild) for (auto x : *vec[v]) { cnt[col[x]]++; vec[u]-&gt;push_back(x); } // now (*cnt[v])[c] is the number of vertices in subtree of vertex v that  // has color c. You can answer the queries easily.  // note that in this step *vec[v] contains all of the subtree of vertex v.  if (keep == 0) for (auto &amp;v : *vec[u]) cnt[col[v]]--; }

