// 数组下标必须从1开始  // 单点更新区间查询 int BIT[maxn]; inline int lowb(int x) { return x &amp; (-x); } inline int query(int l,int r){ int ret = 0; for(int i=l-1;i&gt;0;i-=lowb(i)) ret -= BIT[i]; for(int i=r;i&gt;0;i-=lowb(i)) ret += BIT[i]; return ret; } inline void update(int x,int y,int n){ for(int i=x;i&lt;=n;i+=lowb(i)) BIT[i] += y; } //区间更新单点查询 int diff[maxn]; inline int lowb(int x) {return x &amp;(-x);} inline int query(int x){ int ret = 0; for(int i=x;i&gt;0;i-=lowb(i)) ret += diff[i]; return ret; } inline void update(int l,int r,int val,int n){ for(int i=l;i&lt;=n;i+=lowb(i)) diff[i] += val; for(int i=r+1;i&lt;=n;i+=lowb(i)) diff[i] -= val; }
